// Recuperar timestamp actual del nodo anterior
const tsActual = $('📅 Calcular ventana de tiempo').first().json.tsActual;
const resultado = [];

for (const item of $input.all()) {
  const cita = item.json;
  if (!cita.fecha_cita || !cita.hora || !cita.chat_id) continue;

  // Construir timestamp de la cita y calcular diferencia en horas
  const tsCita = new Date(cita.fecha_cita + 'T' + cita.hora + ':00').getTime();
  const diffHoras = (tsCita - tsActual) / (1000 * 60 * 60);

  // Ventana de ±30 min alrededor de cada hito
  let accion = null;
  if      (diffHoras >= 47.5 && diffHoras < 48.5) accion = 'recordatorio_48h';
  else if (diffHoras >= 23.5 && diffHoras < 24.5) accion = 'recordatorio_24h';
  else if (diffHoras >=  1.5 && diffHoras <  2.5) accion = 'recordatorio_2h';

  if (accion) {
    resultado.push({
      json: {
        accion,
        chatId:      String(cita.chat_id),
        nombre:      cita.nombre_paciente || cita.nombre || 'Paciente',
        tratamiento: cita.tratamiento || cita.servicio || '',
        fecha:       cita.fecha_cita,
        hora:        cita.hora,
        idioma:      cita.idioma || 'es'
      }
    });
  }
}

// Array vacío detiene la ejecución si no hay nada que enviar
if (resultado.length === 0) return [];
return resultado;
